function DefaultCurrency141() {}
DefaultCurrency141.dataBinding = "/ds/EnterVariableData/curr1";
DefaultCurrency141.tabIndex = -1;
DefaultCurrency141.maxLength = 1;
DefaultCurrency141.isReadOnly = function(){return true;}
DefaultCurrency141.isTemporary = function(){return true;}
DefaultCurrency141.transformToDisplay = function(value){
	return WPS.__CaseManUtils().transformCurrencySymbolToDisplay(value,null,null); }
DefaultCurrency141.transformToModel = function(value){
	return WPS.__CaseManUtils().transformCurrencySymbolToModel(value,null,null); }
